import { useState, useEffect } from "react";
import { useNavigate, useParams } from "react-router-dom";
import "./EmployeeForm.css";

function AddEmployee() {
  const navigate = useNavigate();
  const { id } = useParams();
  const isEditMode = Boolean(id);

  const [activeTab, setActiveTab] = useState("personal");

  const [employee, setEmployee] = useState({
    firstName: "",
    lastName: "",
    empId: "",
    gender: "",
    dob: "",
    maritalStatus: "",
    email: "",
    password: "",

    // Employment
    designation: "",
    department: "",
    salary: "",
    role: "",
    skills: "",
    customSkill: "",

    // Bank
    bankName: "",
    accountNumber: "",
    ifsc: "",

    // Education
    qualification: "",
    university: "",
    passingYear: ""
  });

  // Load employee when editing
  useEffect(() => {
    if (!isEditMode) return;

    const employees = JSON.parse(localStorage.getItem("employees")) || [];
    const found = employees.find((e) => String(e.id) === String(id));

    if (found) {
      setEmployee((prev) => ({
        ...prev,
        ...found
      }));
    }
  }, [id, isEditMode]);

  const handleChange = (e) => {
    setEmployee({
      ...employee,
      [e.target.name]: e.target.value
    });
  };

  // ---------- FINAL SKILL VALUE ----------
  const getFinalSkill = () => {
    return employee.skills === "Other"
      ? employee.customSkill
      : employee.skills;
  };

  // ========================= ADD
  const handleAdd = (e) => {
    e.preventDefault();

    let employees = JSON.parse(localStorage.getItem("employees")) || [];

    const newEmployee = {
      id: Date.now(),
      name: `${employee.firstName} ${employee.lastName}`.trim(),
      ...employee,
      skills: getFinalSkill()
    };

    employees.push(newEmployee);
    localStorage.setItem("employees", JSON.stringify(employees));

    alert("Employee Added Successfully!");
    navigate("/dashboard/employee-details");
  };

  // ========================= UPDATE
  const handleUpdate = (e) => {
    e.preventDefault();

    let employees = JSON.parse(localStorage.getItem("employees")) || [];

    const updated = employees.map((emp) =>
      String(emp.id) === String(id)
        ? {
            ...emp,
            ...employee,
            name: `${employee.firstName} ${employee.lastName}`.trim(),
            skills: getFinalSkill()
          }
        : emp
    );

    localStorage.setItem("employees", JSON.stringify(updated));

    alert("Employee Updated Successfully!");
    navigate("/dashboard/employee-details");
  };

  return (
    <div className="add-employee-page">
      <h2>{isEditMode ? "Edit Employee" : "Add Employee"}</h2>

      {/* TABS */}
      <div className="tabs">
        <button
          className={`tab ${activeTab === "personal" ? "active" : ""}`}
          onClick={() => setActiveTab("personal")}
        >
          PERSONAL
        </button>

        <button
          className={`tab ${activeTab === "employment" ? "active" : ""}`}
          onClick={() => setActiveTab("employment")}
        >
          EMPLOYMENT
        </button>

        <button
          className={`tab ${activeTab === "bank" ? "active" : ""}`}
          onClick={() => setActiveTab("bank")}
        >
          BANK
        </button>

        <button
          className={`tab ${activeTab === "education" ? "active" : ""}`}
          onClick={() => setActiveTab("education")}
        >
          EDUCATION
        </button>
      </div>

      <form
        className="employee-form"
        onSubmit={isEditMode ? handleUpdate : handleAdd}
      >
        {/* PERSONAL TAB */}
        {activeTab === "personal" && (
          <>
            <h3>Personal Details</h3>

            <div className="employee-grid">
              <input
                name="firstName"
                placeholder="First Name"
                value={employee.firstName}
                onChange={handleChange}
              />

              <input
                name="lastName"
                placeholder="Last Name"
                value={employee.lastName}
                onChange={handleChange}
              />

              <input
                name="empId"
                placeholder="Employee ID"
                value={employee.empId}
                onChange={handleChange}
              />

              <select
                name="gender"
                value={employee.gender}
                onChange={handleChange}
              >
                <option>Gender</option>
                <option>Male</option>
                <option>Female</option>
              </select>

              <input
                type="date"
                name="dob"
                value={employee.dob}
                onChange={handleChange}
              />

              <select
                name="maritalStatus"
                value={employee.maritalStatus}
                onChange={handleChange}
              >
                <option>Marital Status</option>
                <option>Single</option>
                <option>Married</option>
              </select>

              <input
                type="email"
                name="email"
                placeholder="Email"
                value={employee.email}
                onChange={handleChange}
              />

              <input
                type="password"
                name="password"
                placeholder="Password"
                value={employee.password}
                onChange={handleChange}
              />
            </div>
          </>
        )}

        {/* EMPLOYMENT TAB */}
        {activeTab === "employment" && (
          <>
            <h3>Employment Details</h3>

            <div className="employee-grid">
              <input
                name="designation"
                placeholder="Designation"
                value={employee.designation}
                onChange={handleChange}
              />

              {/* DEPARTMENT */}
              <select
                name="department"
                value={employee.department}
                onChange={handleChange}
              >
                <option value="">Select Department</option>
                <option>Frontend</option>
                <option>Backend</option>
                <option>QC (Quality Check)</option>
                <option>Database</option>
                <option>IT</option>
                <option>Digital Marketing</option>
                <option>HR</option>
                <option>Sales</option>
                <option>USIT Recruiters</option>
                <option>Business Developers</option>
                <option>Web Developer</option>
              </select>

              <input
                name="salary"
                placeholder="Salary"
                value={employee.salary}
                onChange={handleChange}
              />

              <select
                name="role"
                value={employee.role}
                onChange={handleChange}
              >
                <option>Role</option>
                <option>Employee</option>
                <option>Admin</option>
              </select>

              {/* SKILLS */}
              <select
                name="skills"
                value={employee.skills}
                onChange={handleChange}
              >
                <option value="">Select Skill</option>
                <option>C</option>
                <option>C++</option>
                <option>Java</option>
                <option>Advanced Java</option>
                <option>Python</option>
                <option>NodeJS</option>
                <option>React</option>
                <option>Angular</option>
                <option>MongoDB</option>
                <option>Other</option>
              </select>

              {employee.skills === "Other" && (
                <input
                  name="customSkill"
                  placeholder="Enter Custom Skill"
                  value={employee.customSkill}
                  onChange={handleChange}
                />
              )}
            </div>
          </>
        )}

        {/* BANK TAB */}
        {activeTab === "bank" && (
          <>
            <h3>Bank Details</h3>

            <div className="employee-grid">
              <input
                name="bankName"
                placeholder="Bank Name"
                value={employee.bankName}
                onChange={handleChange}
              />

              <input
                name="accountNumber"
                placeholder="Account Number"
                value={employee.accountNumber}
                onChange={handleChange}
              />

              <input
                name="ifsc"
                placeholder="IFSC Code"
                value={employee.ifsc}
                onChange={handleChange}
              />
            </div>
          </>
        )}

        {/* EDUCATION TAB */}
        {activeTab === "education" && (
          <>
            <h3>Educational Details</h3>

            <div className="employee-grid">
              <select
                name="qualification"
                value={employee.qualification}
                onChange={handleChange}
              >
                <option>Highest Qualification</option>
                <option>B.Tech</option>
                <option>M.Tech</option>
                <option>BSc</option>
                <option>MBA</option>
                <option>MCA</option>
                <option>Diploma</option>
              </select>

              <input
                name="university"
                placeholder="University / College"
                value={employee.university}
                onChange={handleChange}
              />

              <input
                name="passingYear"
                placeholder="Year of Passing"
                value={employee.passingYear}
                onChange={handleChange}
              />
            </div>
          </>
        )}

        <button className="save-btn" type="submit">
          {isEditMode ? "Update Employee" : "Save Employee"}
        </button>
      </form>
    </div>
  );
}

export default AddEmployee;
